SELECT act_group_option_id, act_group_id, option_key, option_html, option_text, structure_json, sort_order FROM act_group_option WHERE status = 1 AND delete_flag = '1' AND act_group_id IN
#{groupId}
ORDER BY act_group_id ASC, sort_order ASC, act_group_option_id ASC

SELECT act_question_answer_id, act_question_id, answer_raw, answer_json, explanation_html, explanation_text, grading_mode FROM act_question_answer WHERE status = 1 AND delete_flag = '1' AND act_question_id IN
#{questionId}
ORDER BY act_question_id ASC, act_question_answer_id ASC
